String originalDigits(String s) {
    StringBuilder result = new StringBuilder();
    int index = 0;
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (isDigit(c)) {
            int num = getNumFromChar(c);
            while (index < num) {
                result.append(index);
                index++;
            }
        }
    }
    return result.toString();
}

